(()=>{"use strict";document.getElementById("loginForm").addEventListener("submit",m=>{m.preventDefault();const k=document.getElementById("phone").value,A=document.getElementById("password").value;(m=>11===m.length)(k)?A.length<6?console.log("密码至少6位"):(console.log("手机号:",k),console.log("密码:",A),alert("登录成功（演示）！")):console.log("手机号格式不正确！必须是11位数字")});const m=document.createElement("img");m.src="data:image/png;base64,",document.querySelector(".login-container").appendChild(m)})();